enum Direction {
  Up,     // 0
  Down,   // 1
  Left,   // 2
  Right,  // 3
}

// Usage
let dir: Direction = Direction.Up;

// Numeric enums support reverse mapping at runtime
console.log(Direction[0]); // 'Up'   — string from number
console.log(Direction.Up); // 0      — number from name

// Custom start value
enum HttpStatus {
  OK      = 200,
  Created = 201,
  NotFound = 404,
  InternalError = 500,
}

// Computed members (initialised at runtime)
enum FileAccess {
  None,
  Read    = 1 << 1,  // 2
  Write   = 1 << 2,  // 4
  ReadWrite = Read | Write, // 6
}

enum Color { Red = 0, Green = 1, Blue = 2 }

// This is a TS error (good)
// const c: Color = 5; // TS2322 with noImplicitAny — but not always!

// The reverse mapping object at runtime:
// { 0: 'Red', 1: 'Green', 2: 'Blue', Red: 0, Green: 1, Blue: 2 }

// A raw number is assignable to a numeric enum — TypeScript doesn't catch this
const fromNetwork: number = 99;
const c: Color = fromNetwork; // No error! But Color[99] is undefined at runtime.

// String enums do NOT have this problem — prefer them when the value matters.

enum OrderStatus {
  Pending  = 'PENDING',
  Active   = 'ACTIVE',
  Shipped  = 'SHIPPED',
  Delivered = 'DELIVERED',
  Cancelled = 'CANCELLED',
}

// Usage
let status: OrderStatus = OrderStatus.Pending;
console.log(status); // 'PENDING'

// No reverse mapping — OrderStatus['PENDING'] is undefined
// This is intentional: each member must be accessed by name

// Type safety: a raw string is NOT assignable to OrderStatus
// const s: OrderStatus = 'PENDING'; // TS2322 — must use OrderStatus.Pending

// Narrowing works correctly
function describe(s: OrderStatus): string {
  switch (s) {
    case OrderStatus.Pending:   return 'Awaiting processing';
    case OrderStatus.Active:    return 'Being processed';
    case OrderStatus.Shipped:   return 'On the way';
    case OrderStatus.Delivered: return 'Received';
    case OrderStatus.Cancelled: return 'Order cancelled';
  }
}

// Emitted from: enum OrderStatus { Pending = 'PENDING', Active = 'ACTIVE' }
var OrderStatus;
(function (OrderStatus) {
    OrderStatus["Pending"] = "PENDING";
    OrderStatus["Active"] = "ACTIVE";
})(OrderStatus || (OrderStatus = {}));

// The bundle always includes this — even if you only use one member.

const enum Direction {
  Up = 'UP',
  Down = 'DOWN',
  Left = 'LEFT',
  Right = 'RIGHT',
}

// Compiled output at a usage site:
// move(Direction.Up)  →  move("UP")
// The Direction object never exists at runtime

const dir = Direction.Up; // Compiled to: const dir = "UP"

// Limitation: const enums cannot be used dynamically
// const key = 'Up';
// Direction[key]; // Error — not supported with const enum
// They also cannot be imported from a separate compiled file without
// verbatimModuleSyntax or isolatedModules workarounds.

// Instead of enum OrderStatus { Pending = 'PENDING', ... }
type OrderStatus = 'PENDING' | 'ACTIVE' | 'SHIPPED' | 'DELIVERED' | 'CANCELLED';

// Works identically in switch exhaustiveness
function describe(s: OrderStatus): string {
  switch (s) {
    case 'PENDING':   return 'Awaiting processing';
    case 'ACTIVE':    return 'Being processed';
    case 'SHIPPED':   return 'On the way';
    case 'DELIVERED': return 'Received';
    case 'CANCELLED': return 'Order cancelled';
  }
}

// Emits nothing — the type is erased entirely
// No bundle cost, no IIFE

// You can derive a union from an as const array
const STATUSES = ['PENDING', 'ACTIVE', 'SHIPPED', 'DELIVERED', 'CANCELLED'] as const;
type OrderStatusAlt = typeof STATUSES[number];
// 'PENDING' | 'ACTIVE' | 'SHIPPED' | 'DELIVERED' | 'CANCELLED'

// Check membership at runtime
const valid = (STATUSES as readonly string[]).includes(value);

// Defining the enum — or use a union
export enum Theme { Light = 'light', Dark = 'dark', System = 'system' }

@Component({
  selector: 'app-icon',
  template: `<span [class]="themeClass">★</span>`,
})
export class IconComponent {
  @Input() theme: Theme = Theme.System;

  get themeClass(): string {
    switch (this.theme) {
      case Theme.Light:  return 'icon--light';
      case Theme.Dark:   return 'icon--dark';
      case Theme.System: return 'icon--system';
    }
  }
}

// Parent template
// <app-icon [theme]="Theme.Dark" />
// Must import Theme into the component that uses it in templates.

import { Component } from '@angular/core';

export enum Severity { Info = 'info', Warn = 'warn', Error = 'error' }

@Component({
  selector: 'app-alert',
  template: `
    <div [class]="'alert alert--' + severity">
      <ng-content />
    </div>
    <!-- Use the enum in template via the class property -->
    <app-alert [severity]="Severity.Error">Something went wrong</app-alert>
  `,
})
export class AlertComponent {
  // Expose the enum to the template
  readonly Severity = Severity;

  @Input() severity: Severity = Severity.Info;
}

// Alternative: use a string literal union — no exposure needed
// @Input() severity: 'info' | 'warn' | 'error' = 'info';
// <app-alert severity="error">...</app-alert>

import { signal } from '@angular/core';

export type LoadState = 'idle' | 'loading' | 'success' | 'error';

// Signal-based state machine using a union (preferred over enum)
export class DataService {
  readonly state = signal<LoadState>('idle');
  readonly error = signal<string | null>(null);

  async load(): Promise<void> {
    this.state.set('loading');
    this.error.set(null);
    try {
      await fetchData();
      this.state.set('success');
    } catch (e) {
      this.error.set(e instanceof Error ? e.message : 'Unknown error');
      this.state.set('error');
    }
  }
}

// Component consumes state
// @if (service.state() === 'loading') { <spinner /> }
// @if (service.state() === 'error') { <p>{{ service.error() }}</p> }

// Technically valid — avoid in practice
enum Mixed {
  No  = 0,
  Yes = 'YES',
}

// After a string member, subsequent members must also be explicitly initialised
// because TypeScript cannot auto-increment from a string
enum Bad {
  A = 'hello',
  B,         // TS1061 — must have an initialiser
}

// Correct numeric pattern: explicit starting value
enum Priority {
  Low    = 1,
  Medium = 2,
  High   = 3,
}

// All constant members
enum Flags {
  None  = 0,
  Read  = 1 << 0,   // 1  — constant expression
  Write = 1 << 1,   // 2
  Exec  = 1 << 2,   // 4
  All   = Read | Write | Exec, // 7
}

// Check flags with bitwise AND
const perm: Flags = Flags.Read | Flags.Write;
const canRead:  boolean = (perm & Flags.Read)  !== 0; // true
const canExec:  boolean = (perm & Flags.Exec)  !== 0; // false

// Computed member (calls a function — runtime value)
function computeOffset(): number { return Date.now() % 100; }

enum WithComputed {
  Fixed = 10,
  Computed = computeOffset(), // evaluated at runtime
  // MustExplicit = ???,      // TS1061 — member after computed must be initialised
  AfterComputed = 99,         // explicit OK
}

function assertNever(x: never): never {
  throw new Error('Unhandled value: ' + JSON.stringify(x));
}

enum LogLevel { Debug = 'DEBUG', Info = 'INFO', Warn = 'WARN', Error = 'ERROR' }

function formatLog(level: LogLevel, message: string): string {
  switch (level) {
    case LogLevel.Debug: return `[DEBUG] ${message}`;
    case LogLevel.Info:  return `[INFO] ${message}`;
    case LogLevel.Warn:  return `[WARN] ${message}`;
    case LogLevel.Error: return `[ERROR] ${message}`;
    default:             return assertNever(level);
  }
}
// If you add LogLevel.Verbose later and forget to add a case,
// TypeScript reports: Type 'LogLevel.Verbose' is not assignable to type 'never'

// Same pattern works with literal unions — preferred approach
type LogLevelStr = 'DEBUG' | 'INFO' | 'WARN' | 'ERROR';

function formatLogStr(level: LogLevelStr, message: string): string {
  switch (level) {
    case 'DEBUG': return `[DEBUG] ${message}`;
    case 'INFO':  return `[INFO] ${message}`;
    case 'WARN':  return `[WARN] ${message}`;
    case 'ERROR': return `[ERROR] ${message}`;
    default:       return assertNever(level);
  }
}

enum Color { Red = 'red', Green = 'green', Blue = 'blue' }

// Get all keys (member names)
type ColorKey = keyof typeof Color; // 'Red' | 'Green' | 'Blue'
const colorKeys = Object.keys(Color) as ColorKey[];

// Get all values
type ColorValue = `${Color}`; // 'red' | 'green' | 'blue'  — template literal trick
const colorValues = Object.values(Color); // ['red', 'green', 'blue']

// Runtime iteration
for (const key of Object.keys(Color) as ColorKey[]) {
  const value: Color = Color[key];
  console.log(key, '->', value); // Red -> red, Green -> green, ...
}

// With as const array (preferred — avoids the enum entirely)
const COLORS = ['red', 'green', 'blue'] as const;
type ColorAlt = typeof COLORS[number]; // 'red' | 'green' | 'blue'
for (const c of COLORS) {
  console.log(c); // fully typed, no intermediate object
}

// Scenario: HTTP method type
// ❌ Enum — more verbose, emits runtime code, harder to use in templates
enum HttpMethod {
  Get    = 'GET',
  Post   = 'POST',
  Put    = 'PUT',
  Delete = 'DELETE',
}

// ✓ Literal union — zero cost, works directly in templates and string contexts
type HttpMethod = 'GET' | 'POST' | 'PUT' | 'DELETE';

// Scenario: binary flags — enum is appropriate
enum Permission {
  None    = 0,
  Read    = 1 << 0,
  Write   = 1 << 1,
  Execute = 1 << 2,
}

function hasPermission(user: Permission, required: Permission): boolean {
  return (user & required) === required;
}

const userPerm = Permission.Read | Permission.Write;
console.log(hasPermission(userPerm, Permission.Read));    // true
console.log(hasPermission(userPerm, Permission.Execute)); // false

// Service under test
type OrderStatus = 'PENDING' | 'ACTIVE' | 'SHIPPED' | 'CANCELLED';

class OrderService {
  private status: OrderStatus = 'PENDING';

  advance(): void {
    switch (this.status) {
      case 'PENDING':  this.status = 'ACTIVE';   break;
      case 'ACTIVE':   this.status = 'SHIPPED';  break;
      case 'SHIPPED':  break; // terminal
      case 'CANCELLED': break;
    }
  }

  cancel(): void { this.status = 'CANCELLED'; }
  getStatus(): OrderStatus { return this.status; }
}

// Jest / Jasmine tests
describe('OrderService', () => {
  it('starts as PENDING', () => {
    const svc = new OrderService();
    expect(svc.getStatus()).toBe('PENDING');
  });

  it('advances PENDING → ACTIVE', () => {
    const svc = new OrderService();
    svc.advance();
    expect(svc.getStatus()).toBe('ACTIVE');
  });

  it('cancels from any state', () => {
    const svc = new OrderService();
    svc.advance(); // ACTIVE
    svc.cancel();
    expect(svc.getStatus()).toBe('CANCELLED');
  });
});
